column.value:
{
  "pageDescription": "Sample Reception - Manifest Import and Verification",
  "dataPoints": {
    "projectInformation": {
      "projectName": {"type": "text", "label": "Project Name", "required": true},
      "studyId": {"type": "text", "label": "Study ID", "required": true}
    },
    "sampleIdentity": {
      "participantId": {"type": "text", "label": "Participant ID", "description": "For clinical samples", "required": false},
      "barcode": {"type": "text", "label": "Barcode", "required": true}
    },
    "collectionMetadata": {
      "collectionSite": {"type": "text", "label": "Collection Site", "required": true},
      "sampleType": {"type": "reference", "label": "Sample Type", "source": "type_of_sample", "required": true},
      "collectionDateTime": {"type": "dateTime", "label": "Collection Date & Time", "required": true}
    },
    "receptionMetadata": {
      "sampleReceivedDate": {"type": "date", "label": "Sample Received Date", "required": true},
      "sampleArrivalTime": {"type": "time", "label": "Sample Arrival Time", "required": true},
      "receivedBy": {"type": "text", "label": "Received By (initial/signature)", "required": true}
    },
    "storageConditions": {
      "storageContainerType": {"type": "text", "label": "Storage Container Type", "required": true},
      "storageTemperatureOnArrival": {"type": "number", "label": "Storage Temperature on Arrival", "unit": "C", "required": true}
    },
    "complianceStatus": {
      "consentStatus": {"type": "choice", "label": "Consent Status", "options": ["Obtained", "Pending", "Not Required", "Waived"], "description": "For clinical trials", "required": false},
      "crfStatus": {"type": "choice", "label": "CRF Status", "options": ["Complete", "Incomplete", "Pending", "Not Applicable"], "description": "Case Report Form status", "required": false}
    },
    "sampleOriginTracking": {
      "sampleOrigin": {"type": "choice", "label": "Sample Origin", "options": ["Human", "Animal", "Environmental", "Food/Beverage"], "required": true},
      "sourceLocationFacility": {"type": "text", "label": "Source Location/Facility", "required": true}
    }
  },
  "csvColumnMapping": {
    "projectNameColumn": "project_name",
    "studyIdColumn": "study_id",
    "participantIdColumn": "participant_id",
    "barcodeColumn": "barcode",
    "collectionSiteColumn": "collection_site",
    "sampleTypeColumn": "sample_type",
    "collectionDateTimeColumn": "collection_date_time",
    "sampleReceivedDateColumn": "sample_received_date",
    "sampleArrivalTimeColumn": "sample_arrival_time",
    "storageContainerTypeColumn": "storage_container_type",
    "storageTemperatureColumn": "storage_temperature_on_arrival",
    "receivedByColumn": "received_by",
    "consentStatusColumn": "consent_status",
    "crfStatusColumn": "crf_status",
    "sampleOriginColumn": "sample_origin",
    "sourceLocationColumn": "source_location_facility"
  },
  "systemActions": ["Generate unique system ID", "Validate barcode format", "Set status: Received - Awaiting Verification"],
  "bulkOperations": {
    "enabled": true,
    "applyToSelected": ["projectName", "studyId", "sampleReceivedDate", "sampleArrivalTime", "receivedBy", "sampleOrigin"]
  },
  "nextPage": "Sample Verification"
}

{
  "pageDescription": "Laboratory Reception and Verification - Quality Control Assessment",
  "dataPoints": {
    "receiptInformation": {
      "receivedDateTime": {"type": "dateTime", "label": "Received Date & Time", "required": true},
      "receivedBy": {"type": "text", "label": "Received By (Staff Name)", "required": true},
      "arrivalTemperature": {"type": "text", "label": "Temperature on Arrival", "required": false},
      "conditionOnArrival": {"type": "text", "label": "Condition on Arrival", "required": false}
    },
    "qcChecklist": {
      "temperatureCompliance": {"type": "boolean", "label": "Temperature compliance (maintained cold chain)", "required": true},
      "volumeAdequacy": {"type": "boolean", "label": "Volume adequacy", "required": true},
      "labelingCorrectness": {"type": "boolean", "label": "Labeling correctness", "required": true},
      "packagingIntegrity": {"type": "boolean", "label": "Triple packaging integrity", "required": true},
      "noContamination": {"type": "boolean", "label": "No contamination signs", "required": true},
      "noLeakage": {"type": "boolean", "label": "No leakage", "required": true},
      "properContainer": {"type": "boolean", "label": "Proper container type", "required": true}
    },
    "qcResult": {
      "qcResult": {"type": "choice", "label": "QC Result", "options": ["Pass", "Fail"], "description": "Auto-calculated based on checklist", "required": true},
      "rejectionReason": {"type": "choice", "label": "Rejection Reason", "options": ["Mislabeling", "Insufficient volume", "Contaminated samples", "Damaged container", "Expired transport medium", "Temperature excursion", "Other"], "description": "Required if QC fails", "required": false},
      "failAction": {"type": "choice", "label": "Action for Failed Sample", "options": ["discard", "proceed_flagged"], "description": "Discard: sample will NOT proceed. Proceed Flagged: keep with remarks.", "required": false},
      "qcRemarks": {"type": "text", "label": "Remarks / Notes", "required": false}
    }
  },
  "systemActions": ["Update sample status based on QC result", "Flag rejected samples", "Mark discarded samples as SKIPPED"],
  "bulkOperations": {
    "enabled": true,
    "applyToSelected": ["receivedDateTime", "receivedBy", "qcResult", "rejectionReason", "failAction"]
  },
  "previousPage": "Sample Reception",
  "nextPage": "Temporary Storage Assignment"
}

{
  "pageDescription": "Sample Storage Assignment - Storage and Environmental Monitoring",
  "storageTypes": {
    "TEMPORARY": {"label": "Temporary Storage", "description": "For samples awaiting processing after initial QC"},
    "LONG_TERM": {"label": "Long-Term Storage", "description": "For processed samples, isolates, DNA/RNA"}
  },
  "dataPoints": {
    "storageType": {"type": "choice", "label": "Storage Type", "options": ["TEMPORARY", "LONG_TERM"], "default": "TEMPORARY", "required": true},
    "storageHierarchy": {
      "storageRoom": {"type": "reference", "label": "Storage Room", "source": "storage_locations", "level": "ROOM", "required": true},
      "storageFreezer": {"type": "reference", "label": "Freezer/Device", "source": "storage_locations", "level": "DEVICE", "required": true},
      "storageShelf": {"type": "reference", "label": "Shelf", "source": "storage_locations", "level": "SHELF", "required": false},
      "storageRack": {"type": "reference", "label": "Rack", "source": "storage_locations", "level": "RACK", "required": false},
      "storageBox": {"type": "reference", "label": "Box", "source": "storage_locations", "level": "BOX", "required": true},
      "storageWell": {"type": "text", "label": "Well/Position", "description": "e.g., A1, B3, H12", "required": true}
    },
    "storageConditions": {
      "storageCondition": {"type": "choice", "label": "Storage Temperature", "options": ["ROOM_TEMP", "REFRIGERATED", "FROZEN_MINUS20", "FROZEN_MINUS80", "LIQUID_NITROGEN", "INCUBATOR_37"], "required": true, "descriptions": {"ROOM_TEMP": "15-25C for isolates on agar", "REFRIGERATED": "2-8C standard", "FROZEN_MINUS20": "-20C freezer", "FROZEN_MINUS80": "-80C ultra-low", "LIQUID_NITROGEN": "-196C cryo", "INCUBATOR_37": "37C cultures"}}
    },
    "assignmentInfo": {
      "assignedBy": {"type": "text", "label": "Assigned By (Staff Initials)", "required": true},
      "assignedDateTime": {"type": "dateTime", "label": "Assigned Date/Time", "required": true},
      "notes": {"type": "text", "label": "Notes", "required": false}
    }
  },
  "environmentalMonitoring": {
    "frequency": "Twice daily (AM/PM) or continuous if automated",
    "deviceId": {"type": "text", "label": "Device/Equipment ID", "required": true},
    "deviceType": {"type": "choice", "label": "Device Type", "options": ["Refrigerator", "Freezer-20", "Freezer-80", "LN2Tank", "Incubator", "ColdRoom"], "required": true},
    "checkTime": {"type": "choice", "label": "Check Time", "options": ["AM", "PM"], "required": true},
    "temperatureValue": {"type": "number", "label": "Temperature Value", "required": true},
    "temperatureUnit": {"type": "choice", "label": "Unit", "options": ["C", "F"], "default": "C", "required": true},
    "checkedBy": {"type": "text", "label": "Checked By (Staff Initials)", "required": true},
    "checkedDateTime": {"type": "dateTime", "label": "Checked Date/Time", "required": true},
    "excursionNotes": {"type": "text", "label": "Excursion Notes", "description": "Document any temperature deviations and corrective actions", "required": false}
  },
  "temperatureRanges": {
    "Refrigerator": {"min": 2, "max": 8, "unit": "C"},
    "Freezer-20": {"min": -25, "max": -15, "unit": "C"},
    "Freezer-80": {"min": -85, "max": -75, "unit": "C"},
    "LN2Tank": {"min": -200, "max": -180, "unit": "C"},
    "Incubator": {"min": 35, "max": 38, "unit": "C"},
    "ColdRoom": {"min": 2, "max": 8, "unit": "C"}
  },
  "systemActions": ["Assign samples to storage wells", "Update box occupancy", "Log temperature readings twice daily", "Alert on out-of-range temperatures", "Track storage type for workflow routing"],
  "bulkOperations": {
    "enabled": true,
    "autoPopulate": true,
    "applyToSelected": ["storageType", "storageRoom", "storageFreezer", "storageShelf", "storageRack", "storageBox", "storageCondition", "assignedBy"]
  },
  "previousPage": "Laboratory Reception & Verification",
  "nextPage": "Sample Processing"
}
